var countBalancedPermutations = function(num) {
    const MOD = 1000000007n;
    const n = num.length;
    const evenCnt = Math.ceil(n / 2);
    const oddCnt = Math.floor(n / 2);
    const cnt = new Array(10).fill(0);
    let total = 0;
    for (const ch of num) {
        const d = ch.charCodeAt(0) - 48;
        cnt[d]++;
        total += d;
    }
    if (total % 2 !== 0) return 0;
    const target = total / 2;
    const maxN = n + 1;
    const fact = new Array(maxN);
    fact[0] = 1n;
    for (let i = 1; i < maxN; i++) fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    function power(a, b, m) {
        a %= m;
        let r = 1n;
        while (b > 0n) {
            if (b & 1n) r = (r * a) % m;
            a = (a * a) % m;
            b >>= 1n;
        }
        return r;
    }
    const invfact = new Array(maxN);
    invfact[maxN - 1] = power(fact[maxN - 1], MOD - 2n, MOD);
    for (let i = maxN - 2; i >= 0; i--) invfact[i] = (invfact[i + 1] * BigInt(i + 1)) % MOD;
    let dp = [];
    for (let j = 0; j <= evenCnt; j++) dp.push(new Array(target + 1).fill(0n));
    dp[0][0] = 1n;
    for (let d = 0; d < 10; d++) {
        const c = cnt[d];
        const ndp = [];
        for (let j = 0; j <= evenCnt; j++) ndp.push(new Array(target + 1).fill(0n));
        for (let j = 0; j <= evenCnt; j++) {
            for (let s = 0; s <= target; s++) {
                const val = dp[j][s];
                if (val === 0n) continue;
                const maxk = Math.min(c, evenCnt - j);
                for (let k = 0; k <= maxk; k++) {
                    const ns = s + k * d;
                    if (ns > target) break;
                    const nj = j + k;
                    ndp[nj][ns] = (ndp[nj][ns] + (val * invfact[k] % MOD) * invfact[c - k]) % MOD;
                }
            }
        }
        dp = ndp;
    }
    const ways = dp[evenCnt][target];
    const ans = (ways * fact[evenCnt] % MOD) * fact[oddCnt] % MOD;
    return Number(ans);
};
